17	package defaultpreemption
18	
19	import (
20		"context"
21		"fmt"
22		"math/rand"
23		"sort"
24	
25		v1 "k8s.io/api/core/v1"
26		policy "k8s.io/api/policy/v1"
27		schedulingapi "k8s.io/api/scheduling/v1alpha2"
28		metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
29		"k8s.io/apimachinery/pkg/labels"
30		"k8s.io/apimachinery/pkg/runtime"
31		"k8s.io/client-go/listers/scheduling/v1alpha2"
32		corev1helpers "k8s.io/component-helpers/scheduling/corev1"
33		"k8s.io/klog/v2"
34		extenderv1 "k8s.io/kube-scheduler/extender/v1"
35		fwk "k8s.io/kube-scheduler/framework"
36		"k8s.io/kubernetes/pkg/scheduler/apis/config"
37		"k8s.io/kubernetes/pkg/scheduler/apis/config/validation"
38		"k8s.io/kubernetes/pkg/scheduler/framework/plugins/feature"
39		"k8s.io/kubernetes/pkg/scheduler/framework/plugins/names"
40		"k8s.io/kubernetes/pkg/scheduler/framework/preemption"
41		"k8s.io/kubernetes/pkg/scheduler/metrics"
42		"k8s.io/kubernetes/pkg/scheduler/util"
43	)
44	
45	// Name of the plugin used in the plugin registry and configurations.
46	const Name = names.DefaultPreemption
47	
48	// IsEligiblePodFunc is a function which may be assigned to the DefaultPreemption plugin.
49	// This may implement rules/filtering around preemption eligibility, which is in addition to
50	// the internal requirement that the victim pod have lower priority than the preemptor pod.
51	// Any customizations should always allow system services to preempt normal pods, to avoid
52	// problems if system pods are unable to find space.
53	type IsEligiblePodFunc func(nodeInfo fwk.NodeInfo, victim fwk.PodInfo, preemptor *v1.Pod) bool
54	
55	// MoreImportantPodFunc is a function which may be assigned to the DefaultPreemption plugin.
56	// Implementations should return true if the first pod is more important than the second pod
57	// and the second one should be considered for preemption before the first one.
58	// For performance reasons, the search for nodes eligible for preemption is done by omitting all
59	// eligible victims from a node then checking whether the preemptor fits on the node without them,
60	// before adding back victims (starting from the most important) that still fit with the preemptor.
61	// The default behavior is to not consider pod affinity between the preemptor and the victims,
62	// as affinity between pods that are eligible to preempt each other isn't recommended.
63	type MoreImportantPodFunc func(pod1, pod2 *v1.Pod) bool
64	
65	// DefaultPreemption is a PostFilter plugin implements the preemption logic.
66	type DefaultPreemption struct {
67		fh   fwk.Handle
68		fts  feature.Features
69		args config.DefaultPreemptionArgs
70	
71		Executor          *preemption.Executor
72		Evaluator         *preemption.Evaluator
73		pgLister          v1alpha2.PodGroupLister
74		podGroupEvaluator *preemption.PodGroupEvaluator
75	
76		// IsEligiblePod returns whether a victim pod is allowed to be preempted by a preemptor pod.
77		// This filtering is in addition to the internal requirement that the victim pod have lower
78		// priority than the preemptor pod. Any customizations should always allow system services
79		// to preempt normal pods, to avoid problems if system pods are unable to find space.
80		IsEligiblePod IsEligiblePodFunc
81	
82		// MoreImportantPod is used to sort eligible victims in-place in descending order of highest to
83		// lowest importance. Pods with higher importance are less likely to be preempted.
84		// The default behavior is to order pods by descending priority, then descending runtime duration
85		// for pods with equal priority.
86		MoreImportantPod MoreImportantPodFunc
87	}
88	
89	var _ fwk.PostFilterPlugin = &DefaultPreemption{}
90	var _ fwk.PreEnqueuePlugin = &DefaultPreemption{}
91	
92	// Name returns name of the plugin. It is used in logs, etc.
93	func (pl *DefaultPreemption) Name() string {
94		return Name
95	}
96	
97	// New initializes a new plugin and returns it. The plugin type is retained to allow modification.
98	func New(_ context.Context, dpArgs runtime.Object, fh fwk.Handle, fts feature.Features) (*DefaultPreemption, error) {
99		args, ok := dpArgs.(*config.DefaultPreemptionArgs)
100		if !ok {
101			return nil, fmt.Errorf("got args of type %T, want *DefaultPreemptionArgs", dpArgs)
102		}
103		if err := validation.ValidateDefaultPreemptionArgs(nil, args); err != nil {
104			return nil, err
105		}
106	
107		pl := DefaultPreemption{
108			fh:   fh,
109			fts:  fts,
110			args: *args,
111		}
112		pl.Executor = preemption.NewExecutor(fh, fts)
113		pl.Evaluator = preemption.NewEvaluator(Name, fh, &pl, pl.Executor)
114	
115		if pl.fts.EnableWorkloadAwarePreemption || pl.fts.EnableTopologyAwareWorkloadScheduling {
116			pl.pgLister = fh.SharedInformerFactory().Scheduling().V1alpha2().PodGroups().Lister()
117		}
118		if pl.fts.EnableWorkloadAwarePreemption {
119			pl.podGroupEvaluator = preemption.NewPodGroupEvaluator(fh, pl.Executor)
120		}
121	
122		// Default behavior: No additional filtering, beyond the internal requirement that the victim pod
123		// have lower priority than the preemptor pod.
124		pl.IsEligiblePod = func(nodeInfo fwk.NodeInfo, victim fwk.PodInfo, preemptor *v1.Pod) bool {
125			return true
126		}
127	
128		// Default behavior: Sort by descending priority, then by descending runtime duration as secondary ordering.
129		pl.MoreImportantPod = util.MoreImportantPod
130	
131		return &pl, nil
132	}
133	
134	// PostFilter invoked at the postFilter extension point.
135	func (pl *DefaultPreemption) PostFilter(ctx context.Context, state fwk.CycleState, pod *v1.Pod, m fwk.NodeToStatusReader) (*fwk.PostFilterResult, *fwk.Status) {
136		defer func() {
137			metrics.PreemptionAttempts.Inc()
138		}()
139	
140		if pod.Spec.SchedulingGroup != nil && pl.fts.EnableTopologyAwareWorkloadScheduling {
141			pg, err := pl.pgLister.PodGroups(pod.Namespace).Get(*pod.Spec.SchedulingGroup.PodGroupName)
142			if err != nil {
143				return nil, fwk.NewStatus(fwk.Unschedulable, "preemption: pod group for pod not found")
144			}
145			if pg.Spec.SchedulingConstraints != nil {
146				// When TAS is enabled, the default preemption logic needs to be disabled to avoid performing preemption multiple times for each topology option.
147				// The TAS-compatible preemption logic will be implemented in Delayed Preemption KEP 4671 or Workload-aware preemption KEP 5710 features.
148				return nil, fwk.NewStatus(fwk.Unschedulable, "preemption: not eligible due to placement-based pod group scheduling limitation")
149			}
150		}
151		if pod.Spec.SchedulingGroup != nil && pl.fts.EnableWorkloadAwarePreemption {
152			// When WAP is enabled, the default preemption logic needs to be disabled for pod group scheduling to avoid performing preemption in pod by pod cycle
153			// of pod group scheduling. Instead the WAP will be called to perform preemption for the entire pod group.
154			return nil, fwk.NewStatus(fwk.Unschedulable, "preemption: not eligible due to workload aware preemption enabled")
155		}
156	
157		result, status := pl.Evaluator.Preempt(ctx, state, pod, m)
158		msg := status.Message()
159		if len(msg) > 0 {
160			return result, fwk.NewStatus(status.Code(), "preemption: "+msg)
161		}
162		return result, status
163	}
164	
165	func (pl *DefaultPreemption) PreEnqueue(ctx context.Context, p *v1.Pod) *fwk.Status {
166		if !pl.fts.EnableAsyncPreemption {
167			return nil
168		}
169		if p.Spec.SchedulingGroup != nil && pl.fts.EnableWorkloadAwarePreemption {
170			pg, err := pl.pgLister.PodGroups(p.Namespace).Get(*p.Spec.SchedulingGroup.PodGroupName)
171			// If the pg is not found do not block the pod. It's not a default preemption responsibility
172			// to block pods from pod group without pg from entering the queue.
173			if err != nil {
174				return nil
175			}
176			if pl.Executor.IsPodGroupRunningPreemption(pg.GetUID()) {
177				return fwk.NewStatus(fwk.UnschedulableAndUnresolvable, "waiting for the preemption for this pod group to be finished")
178			}
179			return nil
180		}
181	
182		if pl.Executor.IsPodRunningPreemption(p.GetUID()) {
183			return fwk.NewStatus(fwk.UnschedulableAndUnresolvable, "waiting for the preemption for this pod to be finished")
184		}
185		return nil
186	}
187	
188	// EventsToRegister returns the possible events that may make a Pod
189	// failed by this plugin schedulable.
190	func (pl *DefaultPreemption) EventsToRegister(_ context.Context) ([]fwk.ClusterEventWithHint, error) {
191		if pl.fts.EnableAsyncPreemption {
192			return []fwk.ClusterEventWithHint{
193				// We need to register the event to tell the scheduling queue that the pod could be un-gated after some Pods' deletion.
194				{Event: fwk.ClusterEvent{Resource: fwk.AssignedPod, ActionType: fwk.Delete}, QueueingHintFn: pl.isPodSchedulableAfterAssignedPodDeletion},
195			}, nil
196		}
197	
198		// When the async preemption is disabled, PreEnqueue always returns nil, and hence pods never get rejected by this plugin.
199		return nil, nil
200	}
201	
202	// isPodSchedulableAfterAssignedPodDeletion returns the queueing hint for the pod after the assigned pod deletion event,
203	// which always return Skip.
204	// The default preemption plugin is a bit tricky;
205	// the pods rejected by it are the ones that have run/are running the preemption asynchronously.
206	// And, those pods should always have the other plugins in pInfo.UnschedulablePlugins
207	// which failure will be resolved by the preemption.
208	// The reason why we return Skip here is that the preemption plugin should not make the decision of when to requeueing Pods,
209	// and rather, those plugins should be responsible for that.
210	func (pl *DefaultPreemption) isPodSchedulableAfterAssignedPodDeletion(logger klog.Logger, pod *v1.Pod, oldObj, newObj interface{}) (fwk.QueueingHint, error) {
211		return fwk.QueueSkip, nil
212	}
213	
214	// calculateNumCandidates returns the number of candidates the FindCandidates
215	// method must produce from dry running based on the constraints given by
216	// <minCandidateNodesPercentage> and <minCandidateNodesAbsolute>. The number of
217	// candidates returned will never be greater than <numNodes>.
218	func (pl *DefaultPreemption) calculateNumCandidates(numNodes int32) int32 {
219		n := (numNodes * pl.args.MinCandidateNodesPercentage) / 100
220		if n < pl.args.MinCandidateNodesAbsolute {
221			n = pl.args.MinCandidateNodesAbsolute
222		}
223		if n > numNodes {
224			n = numNodes
225		}
226		return n
227	}
228	
229	// getOffsetRand is a dedicated random source for GetOffsetAndNumCandidates calls.
230	// It defaults to rand.Int31n, but is a package variable so it can be overridden to make unit tests deterministic.
231	var getOffsetRand = rand.Int31n
232	
233	// GetOffsetAndNumCandidates chooses a random offset and calculates the number
234	// of candidates that should be shortlisted for dry running preemption.
235	func (pl *DefaultPreemption) GetOffsetAndNumCandidates(numNodes int32) (int32, int32) {
236		return getOffsetRand(numNodes), pl.calculateNumCandidates(numNodes)
237	}
238	
239	// This function is not applicable for out-of-tree preemption plugins that exercise
240	// different preemption candidates on the same nominated node.
241	func (pl *DefaultPreemption) CandidatesToVictimsMap(candidates []preemption.Candidate) map[string]*extenderv1.Victims {
242		m := make(map[string]*extenderv1.Victims, len(candidates))
243		for _, c := range candidates {
244			m[c.Name()] = c.Victims()
245		}
246		return m
247	}
248	
249	// SelectVictimsOnNode finds minimum set of pods on the given node that should be preempted in order to make enough room
250	// for "pod" to be scheduled.
251	func (pl *DefaultPreemption) SelectVictimsOnNode(
252		ctx context.Context,
253		state fwk.CycleState,
254		pod *v1.Pod,
255		nodeInfo fwk.NodeInfo,
256		pdbs []*policy.PodDisruptionBudget) ([]*v1.Pod, int, *fwk.Status) {
257		logger := klog.FromContext(ctx)
258		var potentialVictims []fwk.PodInfo
259		removePod := func(rpi fwk.PodInfo) error {
260			if err := nodeInfo.RemovePod(logger, rpi.GetPod()); err != nil {
261				return err
262			}
263			status := pl.fh.RunPreFilterExtensionRemovePod(ctx, state, pod, rpi, nodeInfo)
264			if !status.IsSuccess() {
265				return status.AsError()
266			}
267			return nil
268		}
269		addPod := func(api fwk.PodInfo) error {
270			nodeInfo.AddPodInfo(api)
271			status := pl.fh.RunPreFilterExtensionAddPod(ctx, state, pod, api, nodeInfo)
272			if !status.IsSuccess() {
273				return status.AsError()
274			}
275			return nil
276		}
277		// As the first step, remove all pods eligible for preemption from the node and
278		// check if the given pod can be scheduled without them present.
279		for _, pi := range nodeInfo.GetPods() {
280			if pl.isPreemptionAllowed(nodeInfo, pi, pod) {
281				potentialVictims = append(potentialVictims, pi)
282			}
283		}
284		for _, pi := range potentialVictims {
285			if err := removePod(pi); err != nil {
286				return nil, 0, fwk.AsStatus(err)
287			}
288		}
289	
290		// No potential victims are found, and so we don't need to evaluate the node again since its state didn't change.
291		if len(potentialVictims) == 0 {
292			return nil, 0, fwk.NewStatus(fwk.UnschedulableAndUnresolvable, "No preemption victims found for incoming pod")
293		}
294	
295		// If the new pod does not fit after removing all the eligible pods,
296		// we are almost done and this node is not suitable for preemption. The only
297		// condition that we could check is if the "pod" is failing to schedule due to
298		// inter-pod affinity to one or more victims, but we have decided not to
299		// support this case for performance reasons. Having affinity to lower
300		// importance (priority) pods is not a recommended configuration anyway.
301		if status := pl.fh.RunFilterPluginsWithNominatedPods(ctx, state, pod, nodeInfo); !status.IsSuccess() {
302			return nil, 0, status
303		}
304		var victims []fwk.PodInfo
305		numViolatingVictim := 0
306		// Sort potentialVictims by descending importance, which ensures reprieve of
307		// higher importance pods first.
308		sort.Slice(potentialVictims, func(i, j int) bool {
309			return pl.MoreImportantPod(potentialVictims[i].GetPod(), potentialVictims[j].GetPod())
310		})
311		// Try to reprieve as many pods as possible. We first try to reprieve the PDB
312		// violating victims and then other non-violating ones. In both cases, we start
313		// from the highest importance victims.
314		violatingVictims, nonViolatingVictims := filterPodsWithPDBViolation(potentialVictims, pdbs)
315		reprievePod := func(pi fwk.PodInfo) (bool, error) {
316			if err := addPod(pi); err != nil {
317				return false, err
318			}
319			status := pl.fh.RunFilterPluginsWithNominatedPods(ctx, state, pod, nodeInfo)
320			fits := status.IsSuccess()
321			if !fits {
322				if err := removePod(pi); err != nil {
323					return false, err
324				}
325				victims = append(victims, pi)
326				logger.V(5).Info("Pod is a potential preemption victim on node", "pod", klog.KObj(pi.GetPod()), "node", klog.KObj(nodeInfo.Node()))
327			}
328			return fits, nil
329		}
330		for _, p := range violatingVictims {
331			if fits, err := reprievePod(p); err != nil {
332				return nil, 0, fwk.AsStatus(err)
333			} else if !fits {
334				numViolatingVictim++
335			}
336		}
337		// Now we try to reprieve non-violating victims.
338		for _, p := range nonViolatingVictims {
339			if _, err := reprievePod(p); err != nil {
340				return nil, 0, fwk.AsStatus(err)
341			}
342		}
343	
344		// Sort victims after reprieving pods to keep the pods in the victims sorted in order of importance from high to low.
345		if len(violatingVictims) != 0 && len(nonViolatingVictims) != 0 {
346			sort.Slice(victims, func(i, j int) bool { return pl.MoreImportantPod(victims[i].GetPod(), victims[j].GetPod()) })
347		}
348		var victimPods []*v1.Pod
349		for _, pi := range victims {
350			victimPods = append(victimPods, pi.GetPod())
351		}
352		return victimPods, numViolatingVictim, fwk.NewStatus(fwk.Success)
353	}
354	
355	// PodEligibleToPreemptOthers returns one bool and one string. The bool
356	// indicates whether this pod should be considered for preempting other pods or
357	// not. The string includes the reason if this pod isn't eligible.
358	// There're several reasons:
359	//  1. The pod has a preemptionPolicy of Never.
360	//  2. The pod has already preempted other pods and the victims are in their graceful termination period.
361	//     Currently we check the node that is nominated for this pod, and as long as there are
362	//     terminating pods on this node, we don't attempt to preempt more pods.
363	func (pl *DefaultPreemption) PodEligibleToPreemptOthers(_ context.Context, pod *v1.Pod, nominatedNodeStatus *fwk.Status) (bool, string) {
364		if pod.Spec.PreemptionPolicy != nil && *pod.Spec.PreemptionPolicy == v1.PreemptNever {
365			return false, "not eligible due to preemptionPolicy=Never."
366		}
367	
368		nodeInfos := pl.fh.SnapshotSharedLister().NodeInfos()
369		nomNodeName := pod.Status.NominatedNodeName
370		if len(nomNodeName) > 0 {
371			// If the pod's nominated node is considered as UnschedulableAndUnresolvable by the filters,
372			// then the pod should be considered for preempting again.
373			if nominatedNodeStatus.Code() == fwk.UnschedulableAndUnresolvable {
374				return true, ""
375			}
376	
377			if nodeInfo, _ := nodeInfos.Get(nomNodeName); nodeInfo != nil {
378				for _, p := range nodeInfo.GetPods() {
379					if pl.isPreemptionAllowed(nodeInfo, p, pod) && podTerminatingByPreemption(p.GetPod()) {
380						// There is a terminating pod on the nominated node.
381						return false, "not eligible due to a terminating pod on the nominated node."
382					}
383				}
384			}
385		}
386		return true, ""
387	}
388	
389	// OrderedScoreFuncs returns a list of ordered score functions to select preferable node where victims will be preempted.
390	func (pl *DefaultPreemption) OrderedScoreFuncs(ctx context.Context, nodesToVictims map[string]*extenderv1.Victims) []func(node string) int64 {
391		return nil
392	}
393	
394	// isPreemptionAllowed returns whether the victim residing on nodeInfo can be preempted by the preemptor
395	func (pl *DefaultPreemption) isPreemptionAllowed(nodeInfo fwk.NodeInfo, victim fwk.PodInfo, preemptor *v1.Pod) bool {
396		// The victim must have lower priority than the preemptor, in addition to any filtering implemented by IsEligiblePod
397		return corev1helpers.PodPriority(victim.GetPod()) < corev1helpers.PodPriority(preemptor) && pl.IsEligiblePod(nodeInfo, victim, preemptor)
398	}
399	
400	// podTerminatingByPreemption returns true if the pod is in the termination state caused by scheduler preemption.
401	func podTerminatingByPreemption(p *v1.Pod) bool {
402		if p.DeletionTimestamp == nil {
403			return false
404		}
405	
406		for _, condition := range p.Status.Conditions {
407			if condition.Type == v1.DisruptionTarget {
408				return condition.Status == v1.ConditionTrue && condition.Reason == v1.PodReasonPreemptionByScheduler
409			}
410		}
411		return false
412	}
413	
414	// filterPodsWithPDBViolation groups the given "pods" into two groups of "violatingPods"
415	// and "nonViolatingPods" based on whether their PDBs will be violated if they are
416	// preempted.
417	// This function is stable and does not change the order of received pods. So, if it
418	// receives a sorted list, grouping will preserve the order of the input list.
419	func filterPodsWithPDBViolation(podInfos []fwk.PodInfo, pdbs []*policy.PodDisruptionBudget) (violatingPodInfos, nonViolatingPodInfos []fwk.PodInfo) {
420		pdbsAllowed := make([]int32, len(pdbs))
421		for i, pdb := range pdbs {
422			pdbsAllowed[i] = pdb.Status.DisruptionsAllowed
423		}
424	
425		for _, podInfo := range podInfos {
426			pod := podInfo.GetPod()
427			pdbForPodIsViolated := false
428			// A pod with no labels will not match any PDB. So, no need to check.
429			if len(pod.Labels) != 0 {
430				for i, pdb := range pdbs {
431					if pdb.Namespace != pod.Namespace {
432						continue
433					}
434					selector, err := metav1.LabelSelectorAsSelector(pdb.Spec.Selector)
435					if err != nil {
436						// This object has an invalid selector, it does not match the pod
437						continue
438					}
439					// A PDB with a nil or empty selector matches nothing.
440					if selector.Empty() || !selector.Matches(labels.Set(pod.Labels)) {
441						continue
442					}
443	
444					// Existing in DisruptedPods means it has been processed in API server,
445					// we don't treat it as a violating case.
446					if _, exist := pdb.Status.DisruptedPods[pod.Name]; exist {
447						continue
448					}
449					// Only decrement the matched pdb when it's not in its <DisruptedPods>;
450					// otherwise we may over-decrement the budget number.
451					pdbsAllowed[i]--
452					// We have found a matching PDB.
453					if pdbsAllowed[i] < 0 {
454						pdbForPodIsViolated = true
455					}
456				}
457			}
458			if pdbForPodIsViolated {
459				violatingPodInfos = append(violatingPodInfos, podInfo)
460			} else {
461				nonViolatingPodInfos = append(nonViolatingPodInfos, podInfo)
462			}
463		}
464		return violatingPodInfos, nonViolatingPodInfos
465	}
466	
467	// PodGroupPostFilter runs a default preemption for the pod group.
468	func (pl *DefaultPreemption) PodGroupPostFilter(ctx context.Context, pg *schedulingapi.PodGroup, pods []*v1.Pod, pgSchedulingFunc func(ctx context.Context) *fwk.Status) *fwk.Status {
469		return pl.podGroupEvaluator.Preempt(ctx, pg, pods, pgSchedulingFunc)
470	}
